386→	private normalizeCondensedFeatures({
387→		condensedFeatures,
388→	}: {
389→		condensedFeatures: unknown;
390→	}): string[] | null {
391→		if (condensedFeatures === null || condensedFeatures === undefined) {
392→			return null;
393→		}
394→
395→		if (typeof condensedFeatures === 'string') {
396→			return [condensedFeatures];
397→		}
398→
399→		if (Array.isArray(condensedFeatures)) {
400→			return condensedFeatures.map(String);
401→		}
402→
403→		if (typeof condensedFeatures === 'object') {
404→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
405→				Array.isArray(value) ? value.map(String) : [String(value)],
406→			);
407→		}
408→
409→		return [JSON.stringify(condensedFeatures)];
410→	}
