412→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
413→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
414→			condensedFeatures: style.condensed_features,
415→		});
416→		const priceLvlMap: Record<string, string> = {
417→			1: 'Budget',
418→			2: 'Mid-range',
419→			3: 'Premium',
420→		};
421→		const mappedPriceLevel: string | null =
422→			style.price_level && priceLvlMap[String(style.price_level)]
423→				? (priceLvlMap[String(style.price_level)] ?? null)
424→				: (priceLvlMap['2'] ?? null);
425→
426→		const parts: string[] = [
427→			...(style.name ? [this.cleanText({ text: style.name })] : []),
428→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
429→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
430→			...(style.brand?.length
431→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
432→				: []),
433→			...(normalizedCondensedFeatures?.length
434→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
435→				: []),
436→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
437→			...(style.primary_category_name
438→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
439→				: []),
440→			...(style.manufacturer
441→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
442→				: []),
443→			...(style.sub_category_names?.length
444→				? [
445→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
446→					]
447→				: []),
448→			...(style.decoration_method
449→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
450→				: []),
451→			...(style.features
452→				? [`Features: ${this.cleanText({ text: style.features })}`]
453→				: []),
454→		];
455→
456→		const combinedText = parts.filter(Boolean).join('. ');
457→
458→		this.logger.debug(
459→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
460→		);
461→
462→		return combinedText;
463→	}
