465→	private cleanText({ text }: { text: string | null | undefined }): string {
466→		if (!text) return '';
467→		return text
468→			.replace(/\r\n|\r|\n/g, ' ')
469→			.replace(/[*#]+\s?/g, '')
470→			.replace(/<[^>]*>/g, '')
471→			.replace(/\s{2,}/g, ' ')
472→			.trim();
473→	}
