476→		style,
477→	}: {
478→		style: IStylesMvBase;
479→	}): IOpensearchProduct {
480→		return {
481→			_id: style._id,
482→			style_id: style.style_id,
483→			product_id: style.product_id,
484→			name: style.name ?? '',
485→			features: style.features,
486→			general_comments: style.general_comments,
487→			decoration_method: style.decoration_method,
488→			manufacturer: style.manufacturer,
489→			primary_category_id: style.primary_category_id,
490→			primary_category_name: style.primary_category_name,
491→			product_type: style.product_type,
492→			style_type: style.style_type,
493→			broad_category_names: style.broad_category_names,
494→			sub_category_names: style.sub_category_names,
495→			minimum_quantity: style.minimum_quantity,
496→			min_qty: style.min_qty,
497→			default_quote_qty: style.default_quote_qty,
498→			sizes: style.sizes,
499→			turn_time: style.turn_time,
500→			rush_turn_time: style.rush_turn_time,
501→			no_minimum: style.no_minimum ? 1 : 0,
502→			price_level: style.price_level,
503→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
504→			rating_count: style.rating_count,
505→			default_unit_prices: style.default_unit_prices,
506→			colors: style.colors,
507→			style_card_image_url: style.style_card_image_url,
508→			link: style.link,
509→			brand: style.brand,
510→			condensed_features: this.normalizeCondensedFeatures({
511→				condensedFeatures: style.condensed_features,
512→			}),
513→			material: style.material,
514→			status: style.status,
515→			created_at:
516→				style.created_at instanceof Date
517→					? style.created_at.toISOString()
518→					: String(style.created_at),
